// TestLefthookPrePushNoFullTestsStep verifies that the full-tests command has
// been removed from the pre-push hook. The full suite now runs in CI on every
// push; blocking the operator's session-end push for ~168s is duplicate work.
// Operators can run `make test-full` for local pre-push verification.
func TestLefthookPrePushNoFullTestsStep(t *testing.T) {
	data, err := os.ReadFile(filepath.Join("..", "..", "lefthook.yml"))
	require.NoError(t, err)
	content := string(data)

	prePushIdx := strings.Index(content, "pre-push:")
	require.True(t, prePushIdx >= 0, "lefthook.yml must have a pre-push section")

	// Find the next top-level section after pre-push (if any) so we only
	// inspect the pre-push block, not later config.
	prePushSection := content[prePushIdx:]
	assert.NotContains(t, prePushSection, "full-tests:",
		"pre-push hook must not contain the full-tests step (moved to CI + make test-full)")
	assert.NotContains(t, prePushSection, "go test -race -cover ./...",
		"pre-push hook must not run the full race+cover suite (too slow for session-end push)")
}

// TestMakefileHasTestFullTarget verifies the Makefile exposes a test-full
// target that mirrors the CI invocation, giving operators a local opt-in path.
func TestMakefileHasTestFullTarget(t *testing.T) {
	data, err := os.ReadFile(filepath.Join("..", "Makefile"))
	require.NoError(t, err)
	content := string(data)

	assert.Contains(t, content, "test-full:",
		"Makefile must have a test-full target for local pre-push verification")
	assert.Contains(t, content, "go test -race -cover ./...",
		"test-full target must invoke go test -race -cover ./... to mirror CI")
}
